export const sciActivities: Activity[] = [
  {"id":"sci-marker-chromatography","title":"Marker Chromatography","altNames":["Hidden Marker Colors","Coffee Filter Color Lab","Paper Chromatography"],"type":"Quiet","place":"Inside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Watch a single black marker dot split into a rainbow of hidden inks as water climbs the paper.","materials":["Coffee filters, 1-2 per camper","Washable markers, especially black, brown, and dark green","Cups of water, 1 per camper","Scissors","Masking tape","Wooden craft sticks or straws to suspend strips, 1 per camper","Paper towels for the table"],"materialTags":["Coffee filters","Markers","Water source","Scissors","Masking tape","Straws"],"steps":["Cut each coffee filter into a strip about 3 cm wide and 10 cm long, one strip per marker color you want to test.","Draw a fat dot or thick line with a marker about 2 cm up from the bottom edge of the strip, pressing hard so the ink is dark.","Tape the top of the strip to a straw or craft stick laid across the rim of a cup so the strip hangs straight down inside.","Pour just enough water into the cup that the very bottom of the strip touches the water but the ink dot stays ABOVE the waterline.","Watch quietly for 5-10 minutes as the water climbs the paper and drags the ink colors up, fanning them into separate bands.","Lift the strips out, lay them on a paper towel to dry, and compare which markers hid the most colors."],"notes":"Black and brown markers give the most dramatic splits, so steer campers toward those first and let them test 'surprise' colors after. The single biggest mistake is starting the ink dot too low so it dunks straight into the water and washes away, so circle the table and check waterlines before anyone waits. For older grades, have them measure how far each color traveled and calculate a simple ratio against the water front, turning it into a real Rf-value investigation.","safety":"Use only washable markers and remind campers the cup water is for the experiment, not for drinking, since dissolved marker ink looks like juice.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Marker Chromatography","url":"https://www.youtube.com/results?search_query=marker+chromatography+coffee+filter+experiment+for+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Marker Chromatography","url":"https://www.google.com/search?q=marker+chromatography+coffee+filter+experiment+kids"}],"variations":["Run the same brand of black marker from three different manufacturers side by side and predict which company uses the most colors in its ink.","Use rubbing-style alcohol-free hand sanitizer instead of water as the solvent and compare how the bands spread differently.","For g79-g1012, have campers measure each band's travel distance in millimeters, compute Rf values, and build a small data table to identify which markers share the same hidden pigments.","Fold a whole filter into quarters, dot the center with several markers, drip water on the middle, and let the colors bloom into a tie-dye circle."],"subsets":[["Stack two or three filters and cut several strips at once to save time","Keep strips uniform so results are comparable"],[],["Make sure the strip hangs straight and does not touch the cup walls"],["Check every camper's waterline before the timer starts so no dot is submerged"],[],[]]},
  {"id":"sci-baking-soda-volcano","title":"Erupting Baking Soda Volcano","altNames":["Classic Volcano","Baking Soda and Vinegar Eruption","Lava Volcano"],"type":"Water","place":"Outside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":2,"prep":"Medium","blurb":"Build a cardboard mountain around a cup and trigger a foaming lava eruption on command.","materials":["Paper or plastic cups, 1 per camper or small group","Cardboard sheets for the mountain base","Masking tape","Paint and paintbrushes for the mountain","Baking soda, about 2 tablespoons per eruption","Vinegar, about half a cup per eruption","Dish soap, a small squirt per eruption","Red and yellow paint or food coloring for lava color","Paper towels and a tray or bin to catch overflow"],"materialTags":["Paper plates/cups","Cardboard","Masking tape","Paint","Paintbrushes","Baking soda","Vinegar","Water source"],"steps":["Tape a cup upright in the center of a cardboard base, then crumple paper and tape it around the cup to build a sloping mountain shape.","Cover the mountain in masking tape or paper strips and paint it like a volcano, leaving the cup mouth open as the crater.","Once dry, spoon 2 tablespoons of baking soda into the cup and add a small squirt of dish soap and a few drops of red and yellow color.","Set the volcano in a tray or outside on the grass to catch the overflow before you trigger it.","Pour about half a cup of vinegar into the crater and step back as the foaming lava bubbles up and runs down the sides.","Recharge with fresh baking soda and vinegar to erupt again and compare a small pour against a big pour."],"notes":"Painting takes the longest, so split the session into a build-and-paint block and a separate eruption block, or pre-build a few mountains to reuse. The dish soap is what turns a fizz into a thick foaming flow, so do not skip it. For older grades, challenge them to measure ingredient amounts and time the eruption, then graph how the foam height changes with more vinegar, turning a kindergarten classic into a controlled-variable experiment.","safety":"Keep the fizzing foam away from eyes, and run eruptions in a tray or outdoors so the acidic vinegar runoff does not pool where campers sit.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Erupting Baking Soda Volcano","url":"https://www.youtube.com/results?search_query=baking+soda+vinegar+volcano+eruption+experiment+for+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Erupting Baking Soda Volcano","url":"https://www.google.com/search?q=baking+soda+vinegar+volcano+experiment+kids"}],"variations":["Hide the baking soda inside a folded paper-towel 'bomb' so the eruption starts a few seconds after the vinegar hits, surprising the group.","Run a colors contest where each group tints their lava and the camp votes on the most realistic eruption.","For g79-g1012, fix the baking soda at 2 tablespoons and erupt with measured vinegar amounts of a quarter, half, and full cup, timing and recording each to find which gives the longest flow.","Add a drop of warm versus cold vinegar and have campers predict and observe which reacts faster."],"subsets":[["Use a tray under the cardboard so glue and tape mess stays contained"],["Leave the crater fully open or the eruption backs up"],["Pre-measure baking soda into cups for younger groups to speed setup"],[],["Have everyone count down together for a dramatic group launch"],[]]},
  {"id":"sci-lemon-volcano","title":"Lemon Volcano Fizz Lab","altNames":["Citrus Volcano","Fizzing Lemon Experiment","Acid Fruit Reaction"],"type":"Water","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Turn an ordinary lemon into a self-fizzing volcano using only its own juice and baking soda.","materials":["Lemons, 1 per camper or pair, halved","Baking soda, about 1 tablespoon per lemon","Craft sticks or plastic spoons for poking and stirring, 1 per camper","Dish soap, a small squirt per lemon","Food coloring or a drop of paint for color","Trays or paper plates to catch juice","Paper towels"],"materialTags":["Baking soda","Paper plates/cups","Paper towels","Paint"],"steps":["Cut each lemon in half and sit one half cut-side up on a tray, then squish and poke the inside with a craft stick to break the juice pockets.","Drip a little color and a small squirt of dish soap onto the exposed lemon flesh.","Spoon about a tablespoon of baking soda onto the lemon and watch it start to fizz as it hits the juice.","Stir and mash with the craft stick to release more juice and keep the foaming reaction going.","Add a second pinch of baking soda whenever the bubbling slows to recharge the eruption.","Compare a fresh juicy lemon to a dried-out one and notice which fizzes longer."],"notes":"This is a great companion to the vinegar volcano because the acid comes from the fruit itself, so it naturally sets up a 'where does the acid come from' discussion. Squishier, room-temperature lemons react best, so let them warm up out of any cooler first. For older grades, give them limes, oranges, and lemons and have them rank the fruits by how vigorously each fizzes, then connect that to which fruit is most acidic.","safety":"Citrus juice stings cuts and eyes, so have campers with scratched hands wear paper-towel pads or watch, and keep mashed lemon away from faces.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Lemon Volcano Fizz Lab","url":"https://www.youtube.com/results?search_query=lemon+volcano+baking+soda+fizzing+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Lemon Volcano Fizz Lab","url":"https://www.google.com/search?q=lemon+volcano+baking+soda+experiment+kids"}],"variations":["Run a head-to-head between a lemon and a lime to see which citrus erupts more violently and discuss why.","Have campers predict and test whether warm or refrigerated lemons fizz faster.","For g79-g1012, add a strip of red-cabbage-water or pH paper if available, or simply rank lemon, orange, and apple juice by fizz intensity to estimate an acidity order.","Skip the food coloring and instead use a squirt of dish soap only, then time how long the foam lasts versus a no-soap lemon."],"subsets":[["Pre-cut lemons before camp to avoid handing out knives","Loosen the pulp first so juice is ready to react"],[],[],["Encourage steady mashing rather than one big stir"],[],["Set out three lemon conditions for an easy compare-and-contrast"]]},
  {"id":"sci-oobleck-cornstarch","title":"Oobleck Liquid-Solid Lab","altNames":["Cornstarch Goo","Non-Newtonian Slime","Quicksand Goo"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Mix a goo that flows like liquid when slow but snaps solid the instant you hit it.","materials":["Cornstarch, about 1 cup per camper or pair","Water, about half a cup per camper","Mixing bowls or sturdy cups, 1 per camper or pair","Craft sticks or plastic spoons for stirring","Food coloring or a drop of paint, optional","Trays to work over","Paper towels and a water source for cleanup"],"materialTags":["Water source","Paper plates/cups","Paint","Paper towels"],"steps":["Pour about 1 cup of cornstarch into a bowl set on a tray.","Add water a little at a time, stirring after each splash, until the mix is hard to stir but turns runny when you stop pushing.","Stir in a drop of color if you want, mixing it through evenly.","Test it slow by letting the oobleck drip off your fingers like a liquid.","Test it fast by quickly squeezing a handful into a ball, then opening your hand and watching it melt back to liquid.","Smack the surface in the bowl with a flat hand and feel it push back like a solid."],"notes":"The magic ratio is roughly two parts cornstarch to one part water, but campers should adjust by feel because humidity changes it, so coach 'add water slowly, you can't take it out.' Work over trays because hands and tables get coated. For older grades, introduce the term non-Newtonian fluid and have them design a fair test, like timing how long a marble takes to sink in slow-poured versus punched goo, and tie it to real shear-thickening materials like body armor.","safety":"Oobleck dries to a fine powder, so have campers wash hands before touching faces and sweep or wipe spills promptly because dried cornstarch makes floors slippery.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Oobleck Liquid-Solid Lab","url":"https://www.youtube.com/results?search_query=oobleck+cornstarch+non+newtonian+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Oobleck Liquid-Solid Lab","url":"https://www.google.com/search?q=oobleck+cornstarch+experiment+kids"}],"variations":["Make a big shared tub of oobleck and let campers try to run their fingers across the top fast enough to keep them from sinking.","Pour oobleck slowly onto a speaker or a hand-tapped tray to see the surface form temporary peaks.","For g79-g1012, have teams find the exact cornstarch-to-water ratio that lets a coin rest on top for the longest and present their ratio as a tested recipe.","Tint two batches different colors and swirl them to show the goo barely mixes when handled gently."],"subsets":[[],["Stress that the mix should resist the spoon but pool when still","Add water by the spoonful, never all at once"],[],["Hold a handful and watch it ooze between fingers"],["Squeeze hard, then relax, to feel the state change"],[]]},
  {"id":"sci-walking-water","title":"Walking Water Capillary Bridge","altNames":["Walking Rainbow","Color Mixing Water Walk","Capillary Action Cups"],"type":"Quiet","place":"Inside","ageMin":9,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Set up a row of cups and watch colored water climb paper bridges to fill the empty ones in between.","materials":["Plastic or paper cups, 6-7 per setup","Paper towels, 5-6 sheets per setup","Water source","Food coloring or washable markers in red, yellow, and blue","Trays to hold the cup rows","Scissors to trim towel bridges"],"materialTags":["Paper plates/cups","Paper towels","Water source","Markers","Scissors"],"steps":["Line up 6 or 7 cups in a row, fill the 1st, 3rd, 5th, and 7th about three-quarters full of water, and leave the others empty.","Color the water cups in alternating red, yellow, and blue using food coloring or by scribbling marker ink into the water.","Fold or twist each paper towel into a long thin bridge.","Drape a bridge from each full cup over into the empty cup beside it, so every empty cup has two bridges feeding it.","Watch quietly as water wicks up the paper and slowly drips down into the empty cups.","Check back after 20-30 minutes and notice the empty cups have filled with brand-new mixed colors."],"notes":"The result is slow, so set this up early and let it run while campers do something else, then return for the reveal. Paper-towel brand matters, so test your towels beforehand because thin or coated ones wick poorly. For older grades, have them measure cup levels at timed intervals and graph how the water equalizes, then explain capillary action and why the system stops once the levels match.","safety":"Colored water stains clothes and hands, so keep the cup row on a tray well back from the table edge where it cannot be bumped onto laps.","ages":["g46","g79"],"rating":0,"media":[{"title":"Video demos: Walking Water Capillary Bridge","url":"https://www.youtube.com/results?search_query=walking+water+experiment+capillary+action+rainbow+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Walking Water Capillary Bridge","url":"https://www.google.com/search?q=walking+water+capillary+action+experiment+kids"}],"variations":["Bend the cup row into a circle so the last bridge feeds back into the first cup and the color travels all the way around.","Use only red and blue full cups so the empty middle cup turns purple, focusing on a single mixing prediction.","For g79, race two setups, one with single-fold bridges and one with tightly twisted bridges, and measure which design transfers water faster.","Vary the water levels so some cups start much fuller and predict which direction the water will walk."],"subsets":[["Keep cups evenly spaced and close enough for bridges to reach"],["Use primary colors so the in-between cups make secondary colors"],["Twist towels tight for faster wicking"],["Make sure each bridge end actually dips into the water"],[],["Compare the new color in each empty cup to its two neighbors"]]},
  {"id":"sci-surface-tension-penny","title":"Surface Tension Penny Challenge","altNames":["Drops on a Penny","Water Dome Lab","How Many Drops"],"type":"Quiet","place":"Inside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Guess how many water drops a single coin can hold, then build a wobbling dome that defies belief.","materials":["Coins, 1 per camper","Cups of water, 1 per camper","Straws or eyedroppers for dropping water, 1 per camper","Dish soap, a tiny amount per group","Paper towels","Scrap paper for recording guesses and counts"],"materialTags":["Water source","Straws","Paper plates/cups","Paper towels","Paper"],"steps":["Give each camper a dry coin and have them write down a guess for how many drops of water it can hold.","Fill a straw by dipping it in water and capping the top with a finger, then release one drop at a time onto the coin.","Count out loud as each drop lands and watch the water bulge into a dome above the coin's rim.","Keep adding drops until the dome finally bursts and water spills over the edge.","Record the real count next to the guess and try again to beat the number.","Add one tiny drop of dish soap to the water and repeat to see how many fewer drops the coin holds."],"notes":"Most campers guess way too low, so the gap between guess and reality is the hook, and the soap round delivers the payoff by collapsing the count dramatically. Coach a slow, steady drop technique because rushing breaks the dome early. For older grades, have them run multiple trials, average the results, and compare clean water to soapy water as a controlled test of how surfactants break surface tension.","safety":"Keep coins out of the mouths of any younger visitors helping out, and wipe up spilled water immediately so the floor and table do not get slick.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Surface Tension Penny Challenge","url":"https://www.youtube.com/results?search_query=surface+tension+drops+on+a+penny+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Surface Tension Penny Challenge","url":"https://www.google.com/search?q=surface+tension+penny+drops+experiment+kids"}],"variations":["Run a class contest for the single highest drop count and chart everyone's numbers on a board.","Test different coin sizes to see whether a bigger coin really holds proportionally more water.","For g79-g1012, have campers do five trials each with plain water, average them, then five trials with soapy water and report the percent drop in surface tension.","Compare cold water to warm water and predict which holds more drops before the dome breaks."],"subsets":[["Have everyone commit a written guess before the first drop"],["Practice making one clean drop at a time before counting for real"],[],[],["Wipe and dry the coin fully before each new attempt"],["Stir the soap in gently so you do not add bubbles"]]},
  {"id":"sci-oil-water-soap","title":"Oil, Water, and Soap Fireworks","altNames":["Oil and Water Lab","Color Drop Fireworks","Soap Surfactant Demo"],"type":"Quiet","place":"Inside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Float colored droplets on oil, drop them into water, and trigger bursts of swirling color fireworks.","materials":["Clear cups or jars, 1 per camper or pair","Cooking oil, a few tablespoons per camper","Water source","Food coloring in several colors","Small cups or lids for premixing oil and color","Craft sticks for stirring","Dish soap, a small dish per group","Paper towels"],"materialTags":["Paper plates/cups","Water source","Paint","Paper towels"],"steps":["Fill a clear cup about three-quarters full of water.","In a separate small cup, add a few tablespoons of oil and several drops of different food coloring, then stir gently so the color stays in tiny beads inside the oil.","Pour the colored oil on top of the water and watch the oil float in a layer above it.","Wait and watch as each heavy color droplet slowly sinks out of the oil and bursts into the water like a firework.","Once the show slows, dip a craft stick in dish soap and touch it to the surface to see the oil and color suddenly scatter.","Discuss why the oil floated, why the colors waited, and what the soap did."],"notes":"The key trick is stirring the food coloring into oil first so the color enters as slow-falling beads instead of mixing instantly, which is what makes the firework effect, so demo that step clearly. Use clear cups so campers can watch from the side. For older grades, push the explanation into density and polarity, asking why water-based color won't dissolve in oil, and let them test whether more soap clears the oil faster.","safety":"Cooking oil makes floors and tables dangerously slippery, so work over paper towels and wipe any drips on the floor right away.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Oil, Water, and Soap Fireworks","url":"https://www.youtube.com/results?search_query=oil+water+food+coloring+fireworks+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Oil, Water, and Soap Fireworks","url":"https://www.google.com/search?q=oil+water+food+coloring+fireworks+experiment+kids"}],"variations":["Skip the soap and just enjoy a slow, repeated firework show by adding more colored oil beads over time.","Layer the colors one at a time and predict the order they will sink and burst.","For g79-g1012, have campers research and explain density and polarity, then design a test for how soap concentration changes how fast the oil disperses.","Use warm water versus cold water and observe which makes the color droplets fall and spread faster."],"subsets":[[],["Stir gently so color stays as separate beads, not one blob","Use a fresh small cup so the color does not pre-mix with water"],[],["Have campers count how many seconds each droplet takes to drop"],[],["Connect the soap reaction to how dish soap cuts grease on dishes"]]},
  {"id":"sci-ocean-density-layers","title":"Ocean Density Layers","altNames":["Density Tower","Liquid Stacking Lab","Rainbow Density Column"],"type":"Quiet","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Stack salty and plain water into floating colored layers that refuse to mix.","materials":["Clear cups or tall clear bottles, 1 per camper or pair","Salt, several tablespoons per setup","Water source","Food coloring in several colors","Spoons for stirring and gentle pouring, 1 per layer","Small cups for premixing each salt solution","Paper towels","Optional: small light objects like a bead or bottle cap to test floating"],"materialTags":["Paper plates/cups","Water source","Paint","Paper towels"],"steps":["In separate small cups, make several batches of water with different amounts of salt, for example zero, two, and four tablespoons, stirring each until it dissolves.","Add a different food color to each salt batch so you can tell the layers apart.","Start by pouring the saltiest, heaviest colored water into the bottom of your clear cup.","Tilt the cup and very slowly pour the next-saltiest layer down the inside wall or over the back of a spoon so it floats on top instead of mixing.","Add the plain colored water last as the top layer, pouring just as gently.","Hold the finished tower up to the light, then drop a small object in to see which layer it floats on."],"notes":"Slow, gentle pouring over the back of a spoon is everything here, so practice the technique on a scrap cup first and expect a few muddy towers as part of learning. Always go heaviest to lightest from the bottom up. For older grades, have them measure exact salt amounts, predict the float level of test objects before dropping them, and connect the layers to real ocean phenomena like why denser cold salty water sinks beneath warmer water.","safety":"Keep salty water away from eyes and remind campers not to taste it, and mop spills since salt water can be slippery and sticky on floors.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Ocean Density Layers","url":"https://www.youtube.com/results?search_query=salt+water+density+layers+experiment+ocean+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Ocean Density Layers","url":"https://www.google.com/search?q=salt+water+density+column+layers+experiment+kids"}],"variations":["Add cooking oil as a final ultra-light layer on top to extend the tower to four bands.","Make a guessing game where one camper builds the tower and another has to order the colors by density just by looking.","For g79-g1012, have campers compute the approximate density of each solution from the salt and water amounts and predict exactly where a bead or grape will settle, then test.","Build two towers, one warm and one cold, and observe whether temperature alone can create a stable density layer."],"subsets":[["Label each small cup with its salt amount so they do not get swapped","Stir until no salt grains remain on the bottom"],[],["Heaviest layer always goes in first"],["Pour over the back of a spoon to slow the stream","A slow trickle is the difference between layers and a mix"],[],[]]},
  {"id":"sci-milk-vinegar-plastic","title":"Milk and Vinegar Plastic","altNames":["Casein Plastic","Milk Curd Clay","Homemade Bioplastic"],"type":"Craft","place":"Inside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Curdle warm milk with vinegar to mold a real moldable plastic you can shape and keep.","materials":["Warm milk, about 1 cup per camper, heated by a counselor in advance","Vinegar, about 4 teaspoons per cup of milk","Cups and spoons for stirring, 1 set per camper","Paper towels, several per camper","A strainer or extra paper towels to drain curds","Cookie cutters or hands for shaping","Markers and paint for decorating once dry"],"materialTags":["Vinegar","Paper plates/cups","Paper towels","Markers","Paint"],"steps":["A counselor heats milk until very warm but not boiling and pours about a cup into each camper's cup.","Stir 4 teaspoons of vinegar into the warm milk and keep stirring for about a minute.","Watch the milk separate into rubbery white clumps called curds floating in cloudy liquid.","Pour the mixture through a strainer or onto stacked paper towels and press to squeeze out the liquid.","Knead the warm curds together into a dough, then shape it by hand or press it into cookie cutters.","Set the shapes on paper towels to harden over a day or two, then decorate the finished plastic with markers or paint."],"notes":"The milk must be genuinely hot for the curds to form, so have a counselor handle the heating and pouring, then let it cool just enough to touch before kneading. Whole milk makes more plastic than skim. For older grades, frame this as making casein bioplastic and have them test variables like milk fat percentage or vinegar amount against how much usable plastic they harvest, and discuss historic milk-based plastics and modern bioplastics.","safety":"The milk is hot when poured, so an adult controls the heated milk and campers wait until it is only warm before kneading to avoid burns.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Milk and Vinegar Plastic","url":"https://www.youtube.com/results?search_query=milk+vinegar+casein+plastic+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Milk and Vinegar Plastic","url":"https://www.google.com/search?q=milk+vinegar+casein+plastic+experiment+kids"}],"variations":["Press beads or cut shapes and poke a hole with a straw before drying to string them into casein-plastic jewelry.","Compare whole milk, two-percent, and skim to see which yields the most plastic curd.","For g79-g1012, have teams measure the dry weight of plastic produced per cup of milk under different vinegar amounts and graph the yield to find the optimum recipe.","Add a few drops of color to the warm curds before kneading to make tinted plastic."],"subsets":[["Counselor manages all heating and pouring of hot milk"],[],["Curds should look like cottage cheese, not stay liquid"],["Press firmly through paper towels to remove as much liquid as possible","Drier curds make sturdier plastic"],["Work fast while warm because it stiffens as it cools"],[]]},
  {"id":"sci-egg-in-vinegar","title":"Naked Egg Vinegar Lab","altNames":["Rubber Egg","Bouncy Egg","Naked Egg Experiment"],"type":"Quiet","place":"Inside","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Dissolve an eggshell in vinegar over a few warm days to reveal a rubbery, see-through bouncing egg.","materials":["Raw eggs, 1 per camper or group","Vinegar, enough to fully cover each egg","Clear cups or jars, 1 per egg","Spoons to lower and lift eggs","Paper towels","A safe shelf to leave eggs sitting for 2-3 days"],"materialTags":["Vinegar","Paper plates/cups","Paper towels"],"steps":["Gently lower a raw egg into a clear cup using a spoon so the shell does not crack.","Pour in enough vinegar to cover the egg completely and notice the tiny bubbles already forming on the shell.","Label the cup and leave it sitting out for two to three warm days, checking it each day.","On day one, observe and record the bubbles and a faint film on the shell.","After two or three days, carefully spoon out the egg and rinse it under gentle water to wash away the dissolved shell.","Hold the naked rubbery egg up to the light, give it a tiny low bounce on the table, and gently squeeze to feel the membrane."],"notes":"This is a multi-day experiment, so launch it early in the week and build daily check-ins into the schedule, which actually makes it a great recurring observation log. Warm camp rooms speed the reaction nicely. For older grades, have them weigh and measure the egg before and after to quantify how much it grew by osmosis, then extend it by soaking the naked egg in plain water or salty water and predicting whether it swells or shrinks.","safety":"The eggs are raw, so handle them gently to avoid messy breaks, wash hands after touching raw egg, and bounce the finished egg only from a low height over a tray since it will eventually splatter.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Naked Egg Vinegar Lab","url":"https://www.youtube.com/results?search_query=egg+in+vinegar+naked+rubber+egg+experiment+kids"}],"links":[{"label":"CampMinder: 27 summer camp activities","url":"https://campminder.com/resources/27-summer-camp-activities-to-spice-up-the-summer-camp-atmosphere/"},{"label":"More ideas: Naked Egg Vinegar Lab","url":"https://www.google.com/search?q=egg+in+vinegar+naked+rubber+egg+experiment+kids"}],"variations":["After the shell dissolves, move the naked egg into colored water and watch the dye soak through the membrane to tint the egg.","Compare an egg in vinegar to one in plain water to prove the acid, not the soaking, removes the shell.","For g79-g1012, have campers mass the egg before and after, then transfer the naked egg into salt water versus fresh water and measure osmotic shrinking and swelling over another day.","Drop the finished egg from steadily increasing low heights over a tray to find when the membrane finally fails."],"subsets":[["Use a spoon, never fingers, so the shell stays intact"],["Cover the egg fully or part of the shell will survive"],["Write the date so campers track the days passing"],[],["Rinse gently because the membrane tears easily"],["Bounce only a centimeter or two at first"]]},
  {"id":"sci-bubble-science","title":"Bubble Science Lab","altNames":["Giant Bubbles","Bubble Wand Lab","Homemade Bubble Solution"],"type":"Water","place":"Outside","ageMin":9,"ageMax":18,"durationMin":45,"groupMin":8,"groupMax":null,"energy":2,"prep":"Medium","blurb":"Mix your own bubble solution, engineer wands from camp scraps, and chase giant wobbling spheres.","materials":["Dish soap, about 1 cup per batch","Water, about 6 cups per batch","A spoonful of sugar or cornstarch per batch to strengthen bubbles","Wide bins or buckets to hold solution","Pipe cleaners, straws, and yarn to build wands","Paper cups with bottoms removed for blowing","Masking tape","Paper towels"],"materialTags":["Water source","Pipe cleaners","Straws","Yarn","Paper plates/cups","Masking tape","Paper towels"],"steps":["Mix about 1 cup of dish soap into 6 cups of water and stir in a spoonful of sugar or cornstarch, then let the solution rest a few minutes for stronger bubbles.","Bend pipe cleaners into wand loops of different shapes, or thread yarn between two straws to make a giant-bubble wand.","Dip a wand fully into the solution so the whole loop gets coated.","Blow gently or sweep the wand slowly through the air to launch a bubble.","Test different wand shapes and predict whether a square or triangle loop makes a square bubble.","Try the two-straw yarn wand for huge bubbles by opening it slowly into the wind."],"notes":"Letting the solution sit and adding sugar or cornstarch makes a real difference in bubble strength, so mix it before campers arrive at the station. This works best outdoors on a calm, slightly humid day. For older grades, turn wand-building into an engineering challenge where teams compete on biggest bubble and longest-lasting bubble, and prompt them to explain why every bubble is round no matter the wand shape.","safety":"Soapy ground gets slick and soapy solution stings eyes, so set the station on grass, keep wands pointed away from faces, and rinse any eyes that get splashed.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Bubble Science Lab","url":"https://www.youtube.com/results?search_query=homemade+giant+bubble+solution+science+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Bubble Science Lab","url":"https://www.google.com/search?q=homemade+giant+bubble+solution+wand+experiment+kids"}],"variations":["Run a bubble-recipe bake-off where teams tweak soap, water, and sugar ratios and the camp judges which makes the longest-lasting bubble.","Make square, triangle, and star wands and have campers prove that the bubbles still come out round.","For g79-g1012, build the two-straw-and-yarn giant wand, then quantify results by measuring bubble diameter or timing how long bubbles survive under different recipes.","Try catching a bubble on a soapy-gloved hand or wand without popping it."],"subsets":[["Mix before campers arrive and let it rest","Add sugar or cornstarch for thicker, tougher bubbles"],["Twist pipe-cleaner loops tight so they hold shape","Tie yarn between two straws for the giant wand"],[],["Slow sweeping makes bigger bubbles than hard blowing"],[],["Open the giant wand into a light breeze, not a strong wind"]]},
  {"id":"sci-vortex-tornado-bottle","title":"Vortex Bottle Tornado","altNames":["Tornado in a Bottle","Water Vortex Lab","Whirlpool Bottle"],"type":"Water","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Connect two bottles and swirl a spinning water tornado that drains from top to bottom.","materials":["Clear plastic bottles, 2 per setup, labels removed","Water source","Masking tape, several wraps per setup","A small square of cardboard or a bottle cap with a hole, 1 per setup","Scissors or a pushpin to make the connecting hole","Glitter, small beads, or a drop of color to make the swirl visible","Paper towels"],"materialTags":["Water source","Masking tape","Cardboard","Scissors","Paper plates/cups","Pony beads","Paper towels"],"steps":["Fill one clear bottle about two-thirds full of water and add a drop of color and a few small beads so the swirl shows up.","Place a cardboard disc with a small hole punched in its center over the mouth of the full bottle, or use two caps with a hole drilled through.","Set the empty bottle upside down mouth-to-mouth on top and wrap the joint tightly with masking tape so it cannot leak.","Flip the whole thing so the full bottle is on top and set it down to watch the water glug through slowly.","Now flip it again and quickly swirl the top bottle in a fast circle to start a spinning vortex.","Watch the tornado funnel form and time how fast the water drains compared to the no-swirl glug."],"notes":"The connection is the make-or-break step, so tape the joint generously and test over a tray before declaring it sealed. The swirl-versus-no-swirl comparison is the real lesson, so make sure campers try both. For older grades, have them measure drain time with and without a vortex across several trials and explain how the spinning lets air up the center so water flows out faster, connecting it to real drains and whirlpools.","safety":"Use only plastic bottles, never glass, and if you pre-punch the connector holes with a pushpin keep that sharp tool with a counselor and away from campers.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Vortex Bottle Tornado","url":"https://www.youtube.com/results?search_query=tornado+in+a+bottle+water+vortex+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Vortex Bottle Tornado","url":"https://www.google.com/search?q=tornado+in+a+bottle+water+vortex+experiment+kids"}],"variations":["Add glitter or small foam bits and use the tornado to show how debris gets pulled into a whirlpool.","Try different size connecting holes and observe which makes a tighter, faster tornado.","For g79-g1012, time the full drain with no swirl and with a vortex over five trials each, average the results, and report the percentage of time saved by the spin.","Tilt or shake instead of swirling and compare how poorly the water drains without a clean vortex."],"subsets":[["Add color and beads so the funnel is easy to see"],["A small center hole works better than a big one","Counselor punches the holes ahead of time"],["Wrap tape all the way around several times","Test over a tray for leaks before swirling"],[],["Swirl in fast small circles to get the funnel started"],[]]},
  {"id":"sci-balloon-baking-soda","title":"Balloon Inflate Reaction","altNames":["Self-Inflating Balloon","Gas Balloon Experiment","Fizz Balloon Lab"],"type":"Quiet","place":"Both","ageMin":9,"ageMax":18,"durationMin":30,"groupMin":null,"groupMax":null,"energy":2,"prep":"Low","blurb":"Make a balloon blow itself up using only baking soda, vinegar, and the gas they create.","materials":["Balloons, 1-2 per camper","Empty plastic bottles, 1 per camper or pair","Vinegar, about half a cup per bottle","Baking soda, about 2 teaspoons per balloon","A funnel or rolled paper to load the balloon, 1 per group","Spoons for measuring","Tape measure or string to measure balloon size","Paper towels"],"materialTags":["Balloons","Vinegar","Baking soda","Paper plates/cups","Paper","Paper towels"],"steps":["Pour about half a cup of vinegar into an empty plastic bottle.","Use a funnel or rolled paper to spoon about 2 teaspoons of baking soda into a deflated balloon.","Stretch the mouth of the balloon over the top of the bottle without letting the baking soda fall in yet, keeping the balloon flopped to the side.","On a count of three, lift the balloon upright so the baking soda dumps down into the vinegar.","Watch the bottle fizz and the gas it makes rush up to inflate the balloon on its own.","Measure around the inflated balloon with string and compare it to a neighbor's."],"notes":"The trickiest moment is fitting the balloon over the bottle without spilling the powder early, so coach campers to keep the loaded balloon hanging to the side until the count. The gas produced is carbon dioxide, which is a clean tie-in to the volcano station. For older grades, hold the vinegar constant and vary the baking soda across measured trials, then measure balloon circumference each time to graph how reactant amount controls how much gas is produced.","safety":"Use plastic bottles only and keep faces back as the balloon inflates, since an overfilled balloon can pop, and dispose of popped balloon pieces immediately because they are a choking hazard for any younger siblings nearby.","ages":["g46","g79","g1012"],"rating":0,"media":[{"title":"Video demos: Balloon Inflate Reaction","url":"https://www.youtube.com/results?search_query=balloon+baking+soda+vinegar+inflate+experiment+kids"}],"links":[{"label":"Little Bins for Little Hands: summer camp science","url":"https://littlebinsforlittlehands.com/summer-camp-activities/"},{"label":"More ideas: Balloon Inflate Reaction","url":"https://www.google.com/search?q=balloon+baking+soda+vinegar+inflate+experiment+kids"}],"variations":["Race two bottles with different baking soda amounts to see whose balloon inflates biggest.","Replace vinegar with lemon juice and compare how big the balloon gets with a different acid.","For g79-g1012, fix the vinegar at half a cup and test 1, 2, and 3 teaspoons of baking soda across three trials each, measuring balloon circumference to find the point where adding more stops helping.","Try warm vinegar versus cold vinegar and predict which inflates the balloon faster."],"subsets":[[],["A funnel or rolled-paper cone keeps the powder from spilling"],["Keep the balloon flopped sideways so soda stays out of the vinegar"],["Count down so everyone tips at once for a group reaction"],[],["Measure circumference with string, then lay the string against a ruler"]]},
];
